import type { SelectOption } from '@linm-soft-org/linm-web-common-components';

/** Options Select mức xử lý — init-data only (`form-init-data.md`). */
export function resolveProcessingLevelSelectOptions(
  processingLevelOptions: SelectOption[],
  defaultProcessingLevel?: string,
): SelectOption[] {
  if (processingLevelOptions.length > 0) return processingLevelOptions;
  if (defaultProcessingLevel) {
    return [{ value: defaultProcessingLevel, label: `Mức ${defaultProcessingLevel}` }];
  }
  return [];
}

export function formatProcessingLevelFromOptions(
  level: string | undefined,
  options: SelectOption[],
): string {
  if (!level) return '—';
  return options.find(o => String(o.value) === level)?.label ?? '—';
}
