import { useEffect, type RefObject } from 'react';
import { isStandalone } from '../dev/isStandalone';

const MIN_SHELL_PX = 280;

/**
 * Voucher form shell — embedded: flex fill (parent `.content` height).
 * Standalone: chiều cao = viewport còn lại.
 */
export function useVoucherFormShellHeight(
  shellRef: RefObject<HTMLElement | null>,
  enabled = true,
): void {
  useEffect(() => {
    if (!enabled) return undefined;
    const shell = shellRef.current;
    if (!shell) return undefined;

    const apply = () => {
      if (!isStandalone) {
        shell.style.height = '';
        shell.style.maxHeight = '';
        shell.style.flex = '1';
        shell.style.minHeight = '0';
        return;
      }

      const top = Math.max(0, shell.getBoundingClientRect().top);
      const height = Math.max(MIN_SHELL_PX, window.innerHeight - top);
      shell.style.flex = 'none';
      shell.style.height = `${height}px`;
      shell.style.maxHeight = `${height}px`;
    };

    const timer = window.setTimeout(() => {
      apply();
      window.requestAnimationFrame(apply);
    }, 0);

    window.addEventListener('resize', apply);
    window.addEventListener('linm:nav:toggle-mobile', apply);

    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', apply);
      window.removeEventListener('linm:nav:toggle-mobile', apply);
      shell.style.height = '';
      shell.style.maxHeight = '';
      shell.style.flex = '';
      shell.style.minHeight = '';
    };
  }, [shellRef, enabled]);
}
