import React from 'react';
import { Button, formatMoneyVnd, Modal } from '@linm-soft-org/linm-web-common-components';

export type AllocationVarianceConfirmModalProps = {
  isOpen: boolean;
  varianceAmount: number;
  onCancel: () => void;
  onConfirm: () => void;
  'data-testid'?: string;
};

export const AllocationVarianceConfirmModal: React.FC<AllocationVarianceConfirmModalProps> = ({
  isOpen,
  varianceAmount,
  onCancel,
  onConfirm,
  'data-testid': testId = 'allocation-variance-modal',
}) => (
  <Modal
    isOpen={isOpen}
    onClose={onCancel}
    title="Chênh lệch phân bổ"
    size="sm"
    data-testid={testId}
  >
    <p>
      Do làm tròn khi phân bổ giảm giá, chứng từ có chênh lệch{' '}
      <strong>{formatMoneyVnd(varianceAmount)}</strong>.
    </p>
    <p>Số này sẽ ghi vào trường <strong>Chênh lệch</strong> trên chứng từ.</p>
    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8, marginTop: 16 }}>
      <Button variant="secondary" onClick={onCancel} data-testid={`${testId}-cancel`}>
        Hủy
      </Button>
      <Button variant="primary" onClick={onConfirm} data-testid={`${testId}-confirm`}>
        Tiếp tục Lưu
      </Button>
    </div>
  </Modal>
);
